package main

import (
	"errors"
	"fmt"
	"os/exec"
	"regexp"
	"strconv"
)

// MeasureLatency pings the specified host the given number of times and returns the average latency in milliseconds.
// It uses the system 'ping' command via os/exec and parses the output to extract the average RTT.
func MeasureLatency(host string, count int) (float64, error) {
	if host == "" {
		return 0, errors.New("host cannot be empty")
	}
	if count <= 0 {
		return 0, errors.New("count must be positive")
	}

	// Fix 1: Avoid shell injection by passing arguments directly to exec.Command.
	// This removes the dependency on 'bash' and makes the execution safer and more portable.
	cmd := exec.Command("ping", "-c", strconv.Itoa(count), host)
	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("failed to execute ping: %w (output: %s)", err, string(output))
	}

	outputStr := string(output)

	// Fix 2: Improve Regex robustness.
	// The original regex was too strict regarding spacing and decimal points (e.g., it failed on integer ms).
	// This regex handles:
	// - Linux "rtt" and macOS "round-trip" prefixes (case insensitive).
	// - Integers (e.g., 1) and floats (e.g., 1.234).
	// - Variable spacing.
	// It captures the 4 statistics: min, avg, max, mdev/stddev.
	re := regexp.MustCompile(`(?i)(rtt|round-trip).*?=.*?(\d+\.?\d*)/(\d+\.?\d*)/(\d+\.?\d*)/(\d+\.?\d*)\s*ms`)
	matches := re.FindStringSubmatch(outputStr)

	if len(matches) < 4 {
		return 0, errors.New("could not find or parse RTT statistics in ping output")
	}

	// matches[0] is the full string
	// matches[1] is the keyword (rtt/round-trip)
	// matches[2] is min
	// matches[3] is avg
	avgStr := matches[3]
	avg, err := strconv.ParseFloat(avgStr, 64)
	if err != nil {
		return 0, fmt.Errorf("failed to convert average latency to float: %w", err)
	}

	return avg, nil
}

