package main

import (
	"bytes"
	"fmt"
	"os"
	"os/exec"
	"regexp"
	"strconv"
)

// MeasureLatency pings the specified host a given number of times and returns the average latency in milliseconds.
// It uses the system's ping command via os/exec.
func MeasureLatency(host string, count int) (float64, error) {
	if count <= 0 {
		return 0, fmt.Errorf("invalid count: %d. must be greater than 0", count)
	}

	// Construct the command. 
	// Note: "-c" is the standard flag for packet count on Linux and macOS.
	// On Windows, the flag is typically "-n". This implementation targets POSIX environments.
	cmd := exec.Command("ping", "-c", strconv.Itoa(count), host)

	var stdout, stderr bytes.Buffer
	cmd.Stdout = &stdout
	cmd.Stderr = &stderr

	// Run the command
	err := cmd.Run()
	if err != nil {
		return 0, fmt.Errorf("ping command failed: %w, stderr: %s", err, stderr.String())
	}

	output := stdout.String()

	// Parse the output to find the average latency.
	// The ping statistics line usually looks like:
	// rtt min/avg/max/mdev = 1.234/5.678/9.012/1.234 ms
	// or (in newer versions/iputils):
	// round-trip min/avg/max/stddev = 1.234/5.678/9.012/1.234 ms
	// We capture the four numbers separated by slashes.
	re := regexp.MustCompile(`(?:rtt|round-trip) min/avg/max/(?:mdev|stddev) = ([\d\.]+)/([\d\.]+)/([\d\.]+)/([\d\.]+) ms`)
	matches := re.FindStringSubmatch(output)

	if len(matches) < 3 {
		return 0, fmt.Errorf("could not parse average latency from ping output: %s", output)
	}

	// The second capture group (index 2) is the average latency
	avgStr := matches[2]
	avg, err := strconv.ParseFloat(avgStr, 64)
	if err != nil {
		return 0, fmt.Errorf("failed to convert average latency string '%s' to float: %w", avgStr, err)
	}

	return avg, nil
}

func main() {
	// Example configuration
	host := "google.com"
	count := 4

	fmt.Printf("Pinging %s %d times...\n", host, count)

