package main

import (
	"bytes"
	"fmt"
	"os/exec"
	"regexp"
	"runtime"
	"strconv"
)

// MeasureLatency executes the ping command to measure the average network latency.
// It returns the average latency in milliseconds or an error if the command fails or output cannot be parsed.
func MeasureLatency(host string, count int) (float64, error) {
	var cmd *exec.Cmd

	// Determine the correct arguments based on the operating system
	if runtime.GOOS == "windows" {
		// Windows uses -n for count
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	} else {
		// Linux and macOS use -c for count
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	}

	var out bytes.Buffer
	cmd.Stdout = &out

	// Run the ping command
	err := cmd.Run()
	if err != nil {
		return 0, fmt.Errorf("failed to execute ping command: %w", err)
	}

	output := out.String()

	// Parse the output to extract the average latency
	if runtime.GOOS == "windows" {
		// Windows ping output format example:
		// "Packets: Sent = 4, Received = 4, Lost = 0 (0% loss),"
		// "Approximate round trip times in milli-seconds:"
		// "    Minimum = 1ms, Maximum = 2ms, Average = 1ms"
		re := regexp.MustCompile(`Average = (\d+)ms`)
		matches := re.FindStringSubmatch(output)
		if len(matches) < 2 {
			return 0, fmt.Errorf("could not find average latency in Windows ping output")
		}
		return strconv.ParseFloat(matches[1], 64)
	}

	// Unix-like systems (Linux/macOS) ping output format example:
	// "rtt min/avg/max/mdev = 1.234/5.678/9.012/1.234 ms"
	// or
	// "round-trip min/avg/max/stddev = 1.234/5.678/9.012/1.234 ms"
	re := regexp.MustCompile(`min/avg/max(?:/mdev|/stddev)? = [\d.]+/([\d.]+)/[\d.]+`)
	matches := re.FindStringSubmatch(output)
	if len(matches) < 2 {
		return 0, fmt.Errorf("could not find average latency in Unix ping output")
	}

	return strconv.ParseFloat(matches[1], 64)
}

func main() {
	// Example configuration
	host := "google.com"
	count := 4

	// Execute the measurement
	avgLatency, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Printf("Error: %v\n", err)
		return
	}

	// Print the result
	fmt.Printf("Average latency to %s over %d attempts: %.2f ms\n", host, count, avgLatency)
}

