package main

import (
	"errors"
	"fmt"
	"os/exec"
	"regexp"
	"strconv"
)

// MeasureLatency pings the specified host the given number of times and returns the average latency in milliseconds.
// It uses the system 'ping' command via os/exec and parses the output to extract the average RTT.
func MeasureLatency(host string, count int) (float64, error) {
	if host == "" {
		return 0, errors.New("host cannot be empty")
	}
	if count <= 0 {
		return 0, errors.New("count must be positive")
	}

	// Fix: Execute ping directly instead of using bash -c.
	// This is more secure, efficient, and avoids shell injection vulnerabilities.
	// Arguments are passed as a separate slice to handle special characters correctly.
	cmd := exec.Command("ping", "-c", strconv.Itoa(count), host)
	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("failed to execute ping: %w (output: %s)", err, string(output))
	}

	outputStr := string(output)

	// Fix: Improve regex robustness to handle different ping output formats.
	// 1. Supports 'rtt' (Linux) and 'round-trip' (macOS/BSD) prefixes using case-insensitive matching.
	// 2. Makes the 'mdev' or 'stddev' field optional.
	// 3. Allows for both integer and floating point numbers (e.g., '1' or '1.23').
	re := regexp.MustCompile(`(?i)(?:rtt|round-trip)\s+min/avg/max(?:/[\w]+)?\s+=\s+[\d.]+/([\d.]+)/[\d.]+`)
	matches := re.FindStringSubmatch(outputStr)
	if len(matches) < 2 {
		return 0, errors.New("could not find or parse average latency in ping output")
	}

	avgStr := matches[1]
	avg, err := strconv.ParseFloat(avgStr, 64)
	if err != nil {
		return 0, fmt.Errorf("failed to convert average latency '%s' to float: %w", avgStr, err)
	}

	return avg, nil
}

func main() {
	// Example usage
	host := "google.com"
	count := 4

	latency, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Printf("Error measuring latency: %v\n", err)
		return
	}

	fmt.Printf("Average latency to %s: %.2f ms\n", host, latency)
}

