package main

import (
	"errors"
	"fmt"
	"os/exec"
	"regexp"
	"runtime"
	"strconv"
)

// MeasureLatency pings the specified host a given number of times and returns the average latency in milliseconds.
// It uses the os/exec package to run the system's ping command.
func MeasureLatency(host string, count int) (float64, error) {
	if count <= 0 {
		return 0, errors.New("ping count must be greater than 0")
	}

	var cmd *exec.Cmd
	// Determine the correct arguments based on the operating system
	if runtime.GOOS == "windows" {
		// Windows uses -n for the number of pings
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	} else {
		// Linux and macOS use -c for the number of pings
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	}

	// Execute the command and capture combined output (stdout + stderr)
	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("ping command execution failed: %w, output: %s", err, string(output))
	}

	outputStr := string(output)

	if runtime.GOOS == "windows" {
		// Windows ping output example:
		// "Packets: Sent = 4, Received = 4, Lost = 0 (0% loss),\nApproximate round trip times in milli-seconds:\n    Minimum = 10ms, Maximum = 11ms, Average = 10ms"
		re := regexp.MustCompile(`Average\s*=\s*(\d+)ms`)
		matches := re.FindStringSubmatch(outputStr)
		if len(matches) < 2 {
			return 0, errors.New("could not parse average latency from ping output (Windows)")
		}
		avgStr := matches[1]
		return strconv.ParseFloat(avgStr, 64)
	} else {
		// Linux/macOS ping output example:
		// "rtt min/avg/max/mdev = 1.234/5.678/9.012/1.234 ms"
		// or macOS: "round-trip min/avg/max/stddev = 1.234/5.678/9.012/1.234 ms"
		// We look for the sequence "min/avg/max" followed by "=" and numbers. The average is the second number.
		re := regexp.MustCompile(`min/avg/max.*? = [\d\.]+/([\d\.]+)/`)
		matches := re.FindStringSubmatch(outputStr)
		if len(matches) < 2 {
			return 0, errors.New("could not parse average latency from ping output (Unix-like)")
		}
		avgStr := matches[1]
		return strconv.ParseFloat(avgStr, 64)
	}
}

func main() {
	host := "google.com"
	count := 4

	avgLatency, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Printf("Error measuring latency to %s: %v\n", host, err)
		return
	}

	fmt.Printf("Average latency to %s over %d pings: %.2f ms\n", host, count, avgLatency)
}

