package main

import (
	"fmt"
	"os/exec"
	"regexp"
	"runtime"
	"strconv"
)

// MeasureLatency pings the specified host a user-defined number of times
// and returns the average latency in milliseconds.
func MeasureLatency(host string, count int) (float64, error) {
	if count <= 0 {
		return 0, fmt.Errorf("ping count must be greater than 0")
	}

	// Construct the ping command based on the operating system
	var cmd *exec.Cmd
	if runtime.GOOS == "windows" {
		// Windows uses -n for count
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	} else {
		// Linux and macOS use -c for count
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	}

	// Execute the command and capture output
	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("failed to execute ping command: %w", err)
	}

	outputStr := string(output)

	// Parse the output based on the OS to extract average latency
	if runtime.GOOS == "windows" {
		// Windows ping output typically ends with: "Average = 12ms"
		re := regexp.MustCompile(`Average = (\d+)ms`)
		matches := re.FindStringSubmatch(outputStr)
		if len(matches) < 2 {
			return 0, fmt.Errorf("could not parse average latency from ping output")
		}
		return strconv.ParseFloat(matches[1], 64)
	} else {
		// Linux/macOS ping output typically contains a line like:
		// "rtt min/avg/max/mdev = 1.234/5.678/9.012/1.234 ms"
		// We look for the pattern "= number/number/..." and capture the second number (avg)
		re := regexp.MustCompile(`= [\d.]+/([\d.]+)/`)
		matches := re.FindStringSubmatch(outputStr)
		if len(matches) < 2 {
			return 0, fmt.Errorf("could not parse average latency from ping output")
		}
		return strconv.ParseFloat(matches[1], 64)
	}
}

func main() {
	// Example usage of the MeasureLatency function
	host := "google.com"
	count := 4

	avgLatency, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Printf("Error measuring latency to %s: %v\n", host, err)
		return
	}

	fmt.Printf("Average latency for %s over %d pings: %.2f ms\n", host, count, avgLatency)
}

