package main

import (
	"errors"
	"fmt"
	"os/exec"
	"regexp"
	"strconv"
	"strings"
)

// MeasureLatency pings the specified host the given number of times and returns the average latency in milliseconds.
// It uses the system 'ping' command via os/exec and parses the output to extract the average RTT.
func MeasureLatency(host string, count int) (float64, error) {
	if host == "" {
		return 0, errors.New("host cannot be empty")
	}
	if count <= 0 {
		return 0, errors.New("count must be positive")
	}

	// Fix: Execute ping directly instead of via bash -c.
	// This improves security, performance, and portability.
	// Note: This implementation targets Linux/macOS ping syntax.
	cmd := exec.Command("ping", "-c", strconv.Itoa(count), host)
	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("failed to execute ping: %w (output: %s)", err, string(output))
	}

	// Look for the line containing RTT statistics
	outputStr := string(output)
	lines := strings.Split(outputStr, "\n")
	var statsLine string
	for _, line := range lines {
		// Fix: Support both Linux ("rtt") and macOS ("round-trip") output formats
		if strings.Contains(line, "rtt min/avg/max") || strings.Contains(line, "round-trip min/avg/max") {
			statsLine = line
			break
		}
	}

	if statsLine == "" {
		return 0, errors.New("could not find RTT statistics in ping output")
	}

	// Fix: Robust regex to handle:
	// 1. Linux ("rtt") and macOS ("round-trip") prefixes.
	// 2. Linux ("mdev") and macOS ("stddev") suffixes.
	// 3. Integers (e.g., "1 ms") and floats (e.g., "1.234 ms").
	// Example Linux: rtt min/avg/max/mdev = 1.234/2.345/3.456/0.123 ms
	// Example macOS: round-trip min/avg/max/stddev = 1.234/2.345/3.456/0.123 ms
	re := regexp.MustCompile(`(?i)(?:rtt|round-trip)\s+min/avg/max/(?:mdev|stddev)\s+=\s+\d+(?:\.\d+)?/([\d.]+)/\d+(?:\.\d+)?/\d+(?:\.\d+)?\s+ms`)
	matches := re.FindStringSubmatch(statsLine)
	if len(matches) < 2 {
		return 0, fmt.Errorf("failed to parse average latency from ping output (line: %s)", statsLine)
	}

	avgStr := matches[1]
	avg, err := strconv.ParseFloat(avgStr, 64)
	if err != nil {
		return 0, fmt.Errorf("failed to convert average latency to float: %w", err)
	}

	return avg, nil
}

