package main

import (
	"bufio"
	"errors"
	"fmt"
	"os/exec"
	"regexp"
	"runtime"
	"strconv"
	"strings"
)

// MeasureLatency pings the specified host a given number of times and returns the average latency in ms.
func MeasureLatency(host string, count int) (float64, error) {
	if count <= 0 {
		return 0, errors.New("count must be greater than 0")
	}

	// Construct the ping command based on the operating system.
	// Linux/macOS use -c, Windows uses -n.
	var cmd *exec.Cmd
	switch runtime.GOOS {
	case "windows":
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	default:
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	}

	// Execute the command and capture combined stdout/stderr.
	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("ping command failed: %w, output: %s", err, string(output))
	}

	// Parse the output to extract time values.
	// The regex looks for patterns like "time=10.5 ms" or "time=10ms".
	re := regexp.MustCompile(`time=(\d+(\.\d+)?)\s*ms`)

	scanner := bufio.NewScanner(strings.NewReader(string(output)))
	var totalTime float64
	var packetsReceived int

	for scanner.Scan() {
		line := scanner.Text()
		matches := re.FindStringSubmatch(line)
		if len(matches) > 1 {
			// matches[1] contains the numeric value string
			val, err := strconv.ParseFloat(matches[1], 64)
			if err != nil {
				continue
			}
			totalTime += val
			packetsReceived++
		}
	}

	if packetsReceived == 0 {
		return 0, errors.New("no latency data found in ping output")
	}

	averageLatency := totalTime / float64(packetsReceived)
	return averageLatency, nil
}

func main() {
	// Example configuration
	host := "google.com"
	count := 4

	fmt.Printf("Pinging %s %d times...\n", host, count)
	avg, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Printf("Error: %v\n", err)
		return
	}

	fmt.Printf("Average latency: %.2f ms\n", avg)
}

