package main

import (
	"bytes"
	"fmt"
	"os/exec"
	"regexp"
	"runtime"
	"strconv"
)

// MeasureLatency pings the specified host a given number of times
// and returns the average latency in milliseconds.
func MeasureLatency(host string, count int) (float64, error) {
	if count <= 0 {
		return 0, fmt.Errorf("ping count must be positive")
	}

	// Determine the correct arguments for the ping command based on the OS
	var cmd *exec.Cmd
	if runtime.GOOS == "windows" {
		// Windows uses -n for count
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	} else {
		// Linux and macOS use -c for count
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	}

	// Execute the command and capture output
	var stdout, stderr bytes.Buffer
	cmd.Stdout = &stdout
	cmd.Stderr = &stderr

	err := cmd.Run()
	if err != nil {
		return 0, fmt.Errorf("ping command execution failed: %w, stderr: %s", err, stderr.String())
	}

	output := stdout.String()

	// Parse the output to extract the average latency
	var avgLatency float64

	if runtime.GOOS == "windows" {
		// Example Windows output: "Minimum = 1ms, Maximum = 2ms, Average = 3ms"
		re := regexp.MustCompile(`Average = (\d+)ms`)
		matches := re.FindStringSubmatch(output)
		if len(matches) < 2 {
			return 0, fmt.Errorf("could not parse average latency from Windows ping output")
		}
		avgLatency, err = strconv.ParseFloat(matches[1], 64)
		if err != nil {
			return 0, fmt.Errorf("failed to convert latency value: %w", err)
		}
	} else {
		// Example Linux/macOS output: "rtt min/avg/max/mdev = 1.234/5.678/9.012/1.234 ms"
		// We look for the pattern "number/number/number" following an equals sign
		re := regexp.MustCompile(`= ([\d\.]+)/([\d\.]+)/([\d\.]+)`)
		matches := re.FindStringSubmatch(output)
		if len(matches) < 3 {
			return 0, fmt.Errorf("could not parse average latency from Unix ping output")
		}
		// The second capture group is the average
		avgLatency, err = strconv.ParseFloat(matches[2], 64)
		if err != nil {
			return 0, fmt.Errorf("failed to convert latency value: %w", err)
		}
	}

	return avgLatency, nil
}

func main() {
	// Example usage
	host := "google.com"
	count := 4

	latency, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Printf("Error measuring latency to %s: %v\n", host, err)
		return
	}

	fmt.Printf("Average latency to %s over %d pings: %.2f ms\n", host, count, latency)
}

