package main

import (
	"bytes"
	"errors"
	"fmt"
	"os/exec"
	"regexp"
	"runtime"
	"strconv"
)

// MeasureLatency pings the specified host a user-defined number of times
// and returns the average latency in milliseconds.
func MeasureLatency(host string, count int) (float64, error) {
	if count <= 0 {
		return 0, errors.New("ping count must be greater than 0")
	}

	// Determine the correct flag based on the operating system.
	// Linux/macOS use -c, Windows uses -n.
	var countFlag string
	if runtime.GOOS == "windows" {
		countFlag = "-n"
	} else {
		countFlag = "-c"
	}

	// Prepare the command using os/exec.
	cmd := exec.Command("ping", countFlag, strconv.Itoa(count), host)

	var stdout, stderr bytes.Buffer
	cmd.Stdout = &stdout
	cmd.Stderr = &stderr

	// Execute the command.
	err := cmd.Run()
	if err != nil {
		// Check if we have any output despite the error (e.g., some packets lost but some received)
		// If stdout is empty, return the execution error.
		if stdout.Len() == 0 {
			return 0, fmt.Errorf("ping command execution failed: %v, stderr: %s", err, stderr.String())
		}
	}

	output := stdout.String()

	// Parse the output to extract time values.
	// Regex handles:
	// Linux/Mac: "time=0.055 ms"
	// Windows: "time=1ms" or "time<1ms"
	re := regexp.MustCompile(`time[=<](\d+(\.\d+)?)\s*ms`)
	matches := re.FindAllStringSubmatch(output, -1)

	if len(matches) == 0 {
		return 0, errors.New("no latency data found in ping output")
	}

	var totalLatency float64
	for _, match := range matches {
		// match[0] is the full string, match[1] is the first captured group (the number)
		if len(match) > 1 {
			val, err := strconv.ParseFloat(match[1], 64)
			if err != nil {
				continue
			}
			totalLatency += val
		}
	}

	averageLatency := totalLatency / float64(len(matches))
	return averageLatency, nil
}

func main() {
	host := "google.com"
	count := 4

	avg, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Printf("Error measuring latency to %s: %v\n", host, err)
		return
	}

	fmt.Printf("Average latency for %s (%d pings): %.2f ms\n", host, count, avg)
}

