	"fmt"
	"os/exec"
	"regexp"
	"runtime"
	"strconv"
)

// MeasureLatency pings the specified host a given number of times and returns the average latency in milliseconds.
// It uses the os/exec package to run the system's ping command.
func MeasureLatency(host string, count int) (float64, error) {
	if count <= 0 {
		return 0, errors.New("ping count must be a positive integer")
	}

	// Construct the ping command based on the operating system
	var cmd *exec.Cmd
	if runtime.GOOS == "windows" {
		// Windows uses -n for count
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	} else {
		// Linux and macOS use -c for count
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	}

	var stdout, stderr bytes.Buffer
	cmd.Stdout = &stdout
	cmd.Stderr = &stderr

	// Execute the command
	err := cmd.Run()
	if err != nil {
		return 0, fmt.Errorf("ping command failed: %v, stderr: %s", err, stderr.String())
	}

	output := stdout.String()

	// Parse the output to extract the average latency.
	// The output format differs between Windows and Linux/macOS.
	var avgStr string

	if runtime.GOOS == "windows" {
		// Windows output example: "Minimum = 1ms, Maximum = 2ms, Average = 1ms"
		re := regexp.MustCompile(`Average = (\d+)ms`)
		matches := re.FindStringSubmatch(output)
		if len(matches) < 2 {
			return 0, errors.New("could not parse average latency from Windows ping output")
		}
		avgStr = matches[1]
	} else {
		// Linux/macOS output example: "round-trip min/avg/max/stddev = 1.234/5.678/9.012/1.234 ms"
		// or "rtt min/avg/max/mdev = 1.234/5.678/9.012/1.234 ms"
		re := regexp.MustCompile(`(min/avg/max|round-trip min/avg/max).*? = .*?/(\d+\.?\d*)/`)
		matches := re.FindStringSubmatch(output)
		if len(matches) < 3 {
			return 0, errors.New("could not parse average latency from Unix-like ping output")
		}
		avgStr = matches[2]
	}

	latency, err := strconv.ParseFloat(avgStr, 64)
	if err != nil {
		return 0, fmt.Errorf("failed to convert latency string '%s' to float: %v", avgStr, err)
	}

	return latency, nil
}

func main() {
	// Example usage
	host := "google.com"
	count := 4

	fmt.Printf("Measuring latency to %s (%d pings)...\n", host, count)

	avgLatency, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Printf("Error: %v\n", err)
		return
	}

	fmt.Printf("Average Latency: %.2f ms\n", avgLatency)
}

