package main

import (
	"fmt"
	"os"
	"os/exec"
	"regexp"
	"strconv"
	"strings"
)

// MeasureLatency pings the specified host a given number of times and returns the average latency in milliseconds.
// It uses the os/exec package to run the system's ping command.
// Note: This implementation is designed for Unix-like systems (Linux, macOS) using the '-c' flag.
func MeasureLatency(host string, count int) (float64, error) {
	if count <= 0 {
		return 0, fmt.Errorf("ping count must be greater than 0")
	}

	// Execute the ping command.
	// -c count: Stop after sending count packets (Linux/macOS)
	cmd := exec.Command("ping", "-c", strconv.Itoa(count), host)

	// CombinedOutput runs the command and returns its combined standard output and standard error.
	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("failed to execute ping command: %v, output: %s", err, string(output))
	}

	// Parse the output to find latency values.
	// The regex looks for patterns like "time=1.23 ms" or "time=1 ms".
	re := regexp.MustCompile(`time=(\d+(\.\d+)?)\s*ms`)

	lines := strings.Split(string(output), "\n")
	var totalTime float64
	var matchesFound int

	for _, line := range lines {
		// FindStringSubmatch returns a slice holding the text of the leftmost match,
		// and the submatches (in parentheses).
		matches := re.FindStringSubmatch(line)
		if len(matches) > 1 {
			// matches[1] contains the numeric value of the time.
			latency, err := strconv.ParseFloat(matches[1], 64)
			if err != nil {
				// Skip lines where parsing fails, though regex should prevent this.
				continue
			}
			totalTime += latency
			matchesFound++
		}
	}

	if matchesFound == 0 {
		return 0, fmt.Errorf("no latency data found in ping output")
	}

	averageLatency := totalTime / float64(matchesFound)
	return averageLatency, nil
}

func main() {
	// Configuration
	targetHost := "google.com"
	pingCount := 4

	// Measure latency
	avg, err := MeasureLatency(targetHost, pingCount)
	if err != nil {
		fmt.Fprintf(os.Stderr, "Error measuring latency: %v\n", err)
		os.Exit(1)
	}

	// Output result
	fmt.Printf("Average latency to %s (%d pings): %.2f ms\n", targetHost, pingCount, avg)
}

