package main

import (
	"bytes"
	"fmt"
	"os"
	"os/exec"
	"regexp"
	"runtime"
	"strconv"
)

// MeasureLatency pings the specified host a given number of times and returns the average latency in milliseconds.
func MeasureLatency(host string, count int) (float64, error) {
	var cmd *exec.Cmd

	// Determine the correct flag based on the operating system
	// Windows uses -n, while Linux and macOS use -c
	if runtime.GOOS == "windows" {
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	} else {
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	}

	var out bytes.Buffer
	cmd.Stdout = &out

	// Execute the command
	err := cmd.Run()
	if err != nil {
		return 0, fmt.Errorf("failed to execute ping command: %w", err)
	}

	output := out.String()
	var avgStr string

	// Parse the output based on the OS to find the average latency
	if runtime.GOOS == "windows" {
		// Windows output example: "Average = 1ms"
		re := regexp.MustCompile(`Average = ([\d.]+)ms`)
		matches := re.FindStringSubmatch(output)
		if len(matches) > 1 {
			avgStr = matches[1]
		}
	} else {
		// Linux/macOS output example: "round-trip min/avg/max/stddev = 1.234/5.678/9.012/1.234 ms"
		// We look for the pattern: number/number/number/number ms
		re := regexp.MustCompile(`= [\d.]+/([\d.]+)/[\d.]+/[\d.]+ ms`)
		matches := re.FindStringSubmatch(output)
		if len(matches) > 1 {
			avgStr = matches[1]
		}
	}

	if avgStr == "" {
		return 0, fmt.Errorf("could not parse average latency from ping output: %s", output)
	}

	avgLatency, err := strconv.ParseFloat(avgStr, 64)
	if err != nil {
		return 0, fmt.Errorf("failed to parse latency value: %w", err)
	}

	return avgLatency, nil
}

func main() {
	// Example usage
	host := "google.com"
	count := 4

	latency, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Printf("Error measuring latency: %v\n", err)
		os.Exit(1)
	}

	fmt.Printf("Average latency for %s (%d pings): %.2f ms\n", host, count, latency)
}

