package main

import (
	"errors"
	"fmt"
	"os/exec"
	"regexp"
	"strconv"
	"strings"
)

// MeasureLatency pings the specified host the given number of times and returns the average latency in milliseconds.
// It uses the system 'ping' command via os/exec and parses the output to extract the average RTT.
func MeasureLatency(host string, count int) (float64, error) {
	if host == "" {
		return 0, errors.New("host cannot be empty")
	}
	if count <= 0 {
		return 0, errors.New("count must be positive")
	}

	// Fix: Use direct command execution instead of "bash -c" to avoid shell injection risks
	// and improve portability. Arguments are passed as a slice.
	cmd := exec.Command("ping", "-c", strconv.Itoa(count), host)
	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("failed to execute ping: %w (output: %s)", err, string(output))
	}

	// Look for the line containing RTT statistics
	outputStr := string(output)
	lines := strings.Split(outputStr, "\n")
	var statsLine string
	for _, line := range lines {
		// Handle both Linux ("rtt min/avg/max") and macOS ("round-trip min/avg/max") formats
		if strings.Contains(line, "rtt min/avg/max") || strings.Contains(line, "round-trip min/avg/max") {
			statsLine = line
			break
		}
	}

	if statsLine == "" {
		return 0, errors.New("could not find RTT statistics in ping output")
	}

	// Fix: Improve regex to handle integers and floats, and make the 'mdev' field optional.
	// Matches patterns like:
	// rtt min/avg/max/mdev = 1.234/2.345/3.456/4.567 ms
	// round-trip min/avg/max/stddev = 1.234/2.345/3.456/4.567 ms
	// rtt min/avg/max = 1.234/2.345/3.456 ms
	re := regexp.MustCompile(`= ([\d.]+)/([\d.]+)/[\d.]+(?:/[\d.]+)? ms`)
	matches := re.FindStringSubmatch(statsLine)

	// matches[0] is the full match, matches[1] is min, matches[2] is avg
	if len(matches) < 3 {
		return 0, fmt.Errorf("failed to parse average latency from ping output (line: %s)", statsLine)
	}

	avgStr := matches[2]
	avg, err := strconv.ParseFloat(avgStr, 64)
	if err != nil {
		return 0, fmt.Errorf("failed to convert average latency to float: %w", err)
	}

	return avg, nil
}

