package main

import (
	"bufio"
	"fmt"
	"os"
	"os/exec"
	"regexp"
	"runtime"
	"strconv"
	"strings"
)

// MeasureLatency pings the specified host a given number of times
// and returns the average latency in milliseconds.
func MeasureLatency(host string, count int) (float64, error) {
	if count <= 0 {
		return 0, fmt.Errorf("ping count must be positive")
	}

	// Determine the correct flag for the ping command based on the OS
	// Linux/macOS use -c, Windows uses -n
	var args []string
	if runtime.GOOS == "windows" {
		args = []string{"-n", strconv.Itoa(count), host}
	} else {
		args = []string{"-c", strconv.Itoa(count), host}
	}

	// Execute the ping command
	cmd := exec.Command("ping", args...)
	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("failed to execute ping command: %v, output: %s", err, string(output))
	}

	// Parse the output to extract latency times
	// Regex matches patterns like "time=14.2 ms" or "time=14ms"
	re := regexp.MustCompile(`time=(\d+(\.\d+)?)\s*ms`)

	scanner := bufio.NewScanner(strings.NewReader(string(output)))
	var totalTime float64
	var matchesFound int

	for scanner.Scan() {
		line := scanner.Text()
		matches := re.FindStringSubmatch(line)
		if len(matches) > 1 {
			val, err := strconv.ParseFloat(matches[1], 64)
			if err != nil {
				continue // Skip lines with unparseable numbers
			}
			totalTime += val
			matchesFound++
		}
	}

	if err := scanner.Err(); err != nil {
		return 0, fmt.Errorf("error reading ping output: %v", err)
	}

	if matchesFound == 0 {
		return 0, fmt.Errorf("no latency data found in ping output")
	}

	avgLatency := totalTime / float64(matchesFound)
	return avgLatency, nil
}

func main() {
	// Example usage
	host := "google.com"
	count := 4

	fmt.Printf("Pinging %s %d times...\n", host, count)
	latency, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Printf("Error: %v\n", err)
		os.Exit(1)
	}

	fmt.Printf("Average latency: %.2f ms\n", latency)
}

