package main

import (
	"bytes"
	"fmt"
	"os/exec"
	"regexp"
	"strconv"
)

// MeasureLatency executes a ping command to the specified host and returns the average latency in milliseconds.
// It uses the os/exec package to run the system's ping command.
func MeasureLatency(host string, count int) (float64, error) {
	// Execute the ping command.
	// Note: This implementation assumes a Unix-like environment (Linux/macOS) where the count flag is -c.
	// For Windows, the flag would typically be -n.
	cmd := exec.Command("ping", "-c", strconv.Itoa(count), host)

	var stdout, stderr bytes.Buffer
	cmd.Stdout = &stdout
	cmd.Stderr = &stderr

	if err := cmd.Run(); err != nil {
		return 0, fmt.Errorf("ping command failed: %w, stderr: %s", err, stderr.String())
	}

	output := stdout.String()

	// Parse the output to find the average latency.
	// Common format for Linux: rtt min/avg/max/mdev = 1.234/5.678/9.012/1.234 ms
	// Common format for macOS: round-trip min/avg/max/stddev = 1.234/5.678/9.012/1.234 ms
	// We look for the pattern "min/avg/max" which appears as "number/number/number" preceded by an equals sign or space.
	re := regexp.MustCompile(`[= ]([\d.]+)/([\d.]+)/([\d.]+)`)
	matches := re.FindStringSubmatch(output)

	if len(matches) < 4 {
		return 0, fmt.Errorf("could not parse ping output to find average latency")
	}

	// matches[1] is min, matches[2] is avg, matches[3] is max
	avgStr := matches[2]
	avg, err := strconv.ParseFloat(avgStr, 64)
	if err != nil {
		return 0, fmt.Errorf("failed to parse average latency value '%s': %w", avgStr, err)
	}

	return avg, nil
}

func main() {
	// Example usage of the MeasureLatency function
	host := "google.com"
	count := 4

	latency, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Printf("Error measuring latency: %v\n", err)
		return
	}

	fmt.Printf("Average latency to %s: %.2f ms\n", host, latency)
}

