package main

import (
	"fmt"
	"os/exec"
	"regexp"
	"runtime"
	"strconv"
	"strings"
)

// MeasureLatency pings the specified host a user-defined number of times
// and returns the average latency in milliseconds.
// It uses the os/exec package to execute the system's ping command.
func MeasureLatency(host string, count int) (float64, error) {
	if count <= 0 {
		return 0, fmt.Errorf("ping count must be greater than 0")
	}

	// Determine the correct flag for the ping command based on the OS.
	// Linux and macOS use '-c', Windows uses '-n'.
	var cmd *exec.Cmd
	if runtime.GOOS == "windows" {
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	} else {
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	}

	// Run the command and capture combined stdout and stderr.
	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("failed to execute ping command: %v, output: %s", err, string(output))
	}

	// Parse the output to extract latency values.
	// The regex looks for patterns like "time=10.5ms" or "time<1ms" (Windows).
	// It handles both dot and comma as decimal separators.
	re := regexp.MustCompile(`time[=<](\d+[.,]?\d*)\s*ms`)

	lines := strings.Split(string(output), "\n")
	var totalLatency float64
	var packetsReceived int

	for _, line := range lines {
		matches := re.FindStringSubmatch(line)
		if len(matches) > 1 {
			// Normalize decimal separator to dot for parsing
			valStr := strings.Replace(matches[1], ",", ".", 1)
			val, err := strconv.ParseFloat(valStr, 64)
			if err != nil {
				continue
			}
			totalLatency += val
			packetsReceived++
		}
	}

	if packetsReceived == 0 {
		return 0, fmt.Errorf("no ping results found in output")
	}

	averageLatency := totalLatency / float64(packetsReceived)
	return averageLatency, nil
}

func main() {
	// Example usage of the MeasureLatency function
	host := "google.com"
	count := 4

	fmt.Printf("Pinging %s %d times...\n", host, count)
	avg, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Printf("Error: %v\n", err)
		return
	}

	fmt.Printf("Average latency: %.2f ms\n", avg)
}

