// MeasureLatency pings the specified host a given number of times and returns the average latency in ms.
// It uses the system's ping command via os/exec.
// Note: This implementation assumes a Unix-like environment (Linux/macOS) where the count flag is '-c'.
func MeasureLatency(host string, count int) (float64, error) {
	if count <= 0 {
		return 0, fmt.Errorf("ping count must be greater than 0")
	}

	// Execute the ping command.
	// -c sets the number of packets to send.
	cmd := exec.Command("ping", "-c", strconv.Itoa(count), host)

	// CombinedOutput runs the command and returns its combined standard output and standard error.
	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("failed to execute ping command: %v, output: %s", err, string(output))
	}

	// Parse the output to extract the average latency.
	// Standard Unix ping output usually ends with a line like:
	// rtt min/avg/max/mdev = 1.234/5.678/9.012/1.234 ms (Linux)
	// round-trip min/avg/max/stddev = 1.234/5.678/9.012/1.234 ms (macOS)
	outputStr := string(output)
	lines := strings.Split(outputStr, "\n")

	for _, line := range lines {
		// We look for the line containing "avg" which signifies the statistics summary.
		if strings.Contains(line, "avg") {
			// Split the line by '=' to separate the label from the values.
			// Example: "rtt min/avg/max/mdev = 1.234/5.678/9.012/1.234 ms"
			parts := strings.Split(line, "=")
			if len(parts) < 2 {
				continue
			}

			// Get the right side of the '=' and trim whitespace.
			// Example: " 1.234/5.678/9.012/1.234 ms"
			valuesPart := strings.TrimSpace(parts[1])

			// Split by space to separate the metrics from the unit "ms".
			// Example: ["1.234/5.678/9.012/1.234", "ms"]
			tokens := strings.Split(valuesPart, " ")
			if len(tokens) < 1 {
				continue
			}

			// Split the metrics by '/'.
			// Example: ["1.234", "5.678", "9.012", "1.234"]
			// Index 0: min, Index 1: avg, Index 2: max, Index 3: mdev/stddev
			metrics := strings.Split(tokens[0], "/")
			if len(metrics) < 2 {
				continue
			}

			avgStr := metrics[1]
			avg, err := strconv.ParseFloat(avgStr, 64)
			if err != nil {
				return 0, fmt.Errorf("failed to parse average latency value '%s': %v", avgStr, err)
			}

			return avg, nil
		}
	}

	return 0, fmt.Errorf("could not find average latency in ping output")
}

func main() {
	// Example usage
	host := "google.com"
	count := 4

	avgLatency, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Printf("Error: %v\n", err)
		return
	}

