package main

import (
	"errors"
	"fmt"
	"os/exec"
	"regexp"
	"strconv"
	"strings"
)

// MeasureLatency pings the specified host the given number of times and returns the average latency in milliseconds.
// It uses the system 'ping' command via os/exec and parses the output to extract the average RTT.
func MeasureLatency(host string, count int) (float64, error) {
	if host == "" {
		return 0, errors.New("host cannot be empty")
	}
	if count <= 0 {
		return 0, errors.New("count must be positive")
	}

	// Fix: Use direct command execution instead of 'bash -c' to improve portability and security.
	// This avoids shell injection risks and removes the dependency on bash being available.
	cmd := exec.Command("ping", "-c", strconv.Itoa(count), host)
	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("failed to execute ping: %w (output: %s)", err, string(output))
	}

	// Look for the line containing RTT statistics
	outputStr := string(output)
	lines := strings.Split(outputStr, "\n")
	var statsLine string
	for _, line := range lines {
		// Fix: Handle both Linux ("rtt min/avg/max") and macOS ("round-trip min/avg/max") formats.
		if strings.Contains(line, "min/avg/max") || strings.Contains(line, "round-trip") {
			statsLine = line
			break
		}
	}

	if statsLine == "" {
		return 0, errors.New("could not find RTT statistics in ping output")
	}

	// Fix: Improved regex to handle integers (e.g., "1" vs "1.0") and variations in the 4th stat label (mdev vs stddev).
	// The pattern looks for " = min/avg/max" where the values can be integers or floats.
	// Example matches:
	// Linux: rtt min/avg/max/mdev = 1.234/2.345/3.456/0.123 ms
	// macOS: round-trip min/avg/max/stddev = 1.234/2.345/3.456/0.123 ms
	re := regexp.MustCompile(`= ([\d\.]+)/([\d\.]+)/([\d\.]+)`)
	matches := re.FindStringSubmatch(statsLine)

	// We expect at least 4 matches: the full string, min, avg, max.
	if len(matches) < 4 {
		return 0, errors.New("failed to parse average latency from ping output")
	}

	avgStr := matches[2] // The second capture group is the average latency.
	avg, err := strconv.ParseFloat(avgStr, 64)
	if err != nil {
		return 0, fmt.Errorf("failed to convert average latency to float: %w", err)
	}

	return avg, nil
}

