// MeasureLatency executes the system ping command to measure average latency.
// It assumes a Unix-like environment (Linux/macOS) where the ping command supports the '-c' flag.
func MeasureLatency(host string, count int) (float64, error) {
	if count <= 0 {
		return 0, fmt.Errorf("ping count must be positive")
	}

	// Construct the command. 
	// Note: On Windows, the flag is '-n' instead of '-c'. 
	// This implementation targets Unix-like systems as is standard for Go server tools.
	cmd := exec.Command("ping", "-c", strconv.Itoa(count), host)

	// Run the command and capture combined output (stdout + stderr)
	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("failed to execute ping command: %w, output: %s", err, string(output))
	}

	// Parse the output to extract latency times.
	// The regex looks for patterns like "time=24.5 ms" or "time=14 ms".
	re := regexp.MustCompile(`time=(\d+(\.\d+)?)\s*ms`)
	scanner := bufio.NewScanner(strings.NewReader(string(output)))

	var totalTime float64
	var packetsReceived int

	for scanner.Scan() {
		line := scanner.Text()
		matches := re.FindStringSubmatch(line)
		if len(matches) > 1 {
			// matches[1] contains the numeric value of the time
			if val, err := strconv.ParseFloat(matches[1], 64); err == nil {
				totalTime += val
				packetsReceived++
			}
		}
	}

	if err := scanner.Err(); err != nil {
		return 0, fmt.Errorf("error reading ping output: %w", err)
	}

	if packetsReceived == 0 {
		return 0, fmt.Errorf("no latency data found in ping output for host %s", host)
	}

	avgLatency := totalTime / float64(packetsReceived)
	return avgLatency, nil
}

func main() {
	// Example usage
	host := "google.com"
	count := 4

	avg, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Printf("Error measuring latency: %v\n", err)
		return
	}

	fmt.Printf("Average latency for %s (%d pings): %.2f ms\n", host, count, avg)
}

