package main

import (
	"bytes"
	"fmt"
	"os/exec"
	"strconv"
	"strings"
)

// MeasureLatency pings the specified host a given number of times
// and returns the average latency in milliseconds.
// It uses the system's ping command via os/exec.
// Note: This implementation assumes a Unix-like environment (uses -c flag).
func MeasureLatency(host string, count int) (float64, error) {
	if count <= 0 {
		return 0, fmt.Errorf("ping count must be positive")
	}

	// Construct the command. 
	// "-c" is the standard flag for packet count on Linux and macOS.
	// For Windows, this would typically be "-n".
	cmd := exec.Command("ping", "-c", strconv.Itoa(count), host)

	var stdout, stderr bytes.Buffer
	cmd.Stdout = &stdout
	cmd.Stderr = &stderr

	// Run the command
	err := cmd.Run()
	if err != nil {
		return 0, fmt.Errorf("ping command execution failed: %v: %s", err, stderr.String())
	}

	output := stdout.String()
	var totalLatency float64
	var packetsReceived int

	// Parse the output line by line
	lines := strings.Split(output, "\n")
	for _, line := range lines {
		// Standard ping output lines usually contain "time=" followed by the latency and "ms"
		if strings.Contains(line, "time=") && strings.Contains(line, "ms") {
			// Extract the substring after "time="
			timeIndex := strings.Index(line, "time=")
			if timeIndex == -1 {
				continue
			}

			// Get the part after "time="
			timeSubstring := line[timeIndex+5:] // len("time=") is 5

			// The latency is usually followed by a space or "ms". 
			// We split by space to isolate the number.
			timeParts := strings.Fields(timeSubstring)
			if len(timeParts) == 0 {
				continue
			}

			// Clean up the string (remove trailing "ms" if attached without space, though rare)
			timeStr := strings.TrimSuffix(timeParts[0], "ms")

			latency, err := strconv.ParseFloat(timeStr, 64)
			if err != nil {
				// If we can't parse a specific line, we skip it but continue processing others
				continue
			}

			totalLatency += latency
			packetsReceived++
		}
	}

	if packetsReceived == 0 {
		return 0, fmt.Errorf("no valid ping responses received")
	}

	averageLatency := totalLatency / float64(packetsReceived)
	return averageLatency, nil
}

func main() {
	// Example usage
	host := "google.com"
	count := 4

	avg, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Printf("Error measuring latency: %v\n", err)
		return
	}

	fmt.Printf("Average latency for %s over %d pings: %.2f ms\n", host, count, avg)
}

