// MeasureLatency pings the specified host 'count' times and returns the average latency in milliseconds.
// It uses the os/exec package to invoke the system's ping command.
func MeasureLatency(host string, count int) (float64, error) {
	if count <= 0 {
		return 0, fmt.Errorf("ping count must be positive")
	}

	var cmd *exec.Cmd

	// Determine the correct ping arguments based on the operating system
	// Windows uses -n, while Linux and macOS use -c
	if runtime.GOOS == "windows" {
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	} else {
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	}

	var out bytes.Buffer
	var stderr bytes.Buffer
	cmd.Stdout = &out
	cmd.Stderr = &stderr

	// Run the command
	err := cmd.Run()
	if err != nil {
		return 0, fmt.Errorf("ping command failed: %v, stderr: %s", err, stderr.String())
	}

	output := out.String()

	// Parse the output based on the OS
	if runtime.GOOS == "windows" {
		// Windows output example:
		// Packets: Sent = 4, Received = 4, Lost = 0 (0% loss),
		// Minimum = 1ms, Maximum = 2ms, Average = 1ms
		lines := strings.Split(output, "\n")
		for _, line := range lines {
			if strings.Contains(line, "Average") {
				parts := strings.Split(line, "=")
				if len(parts) >= 2 {
					avgStr := strings.TrimSpace(parts[len(parts)-1])
					avgStr = strings.ReplaceAll(avgStr, "ms", "")
					return strconv.ParseFloat(avgStr, 64)
				}
			}
		}
	} else {
		// Linux/macOS output example:
		// round-trip min/avg/max/stddev = 1.234/5.678/9.012/1.234 ms
		lines := strings.Split(output, "\n")
		for _, line := range lines {
			// Look for the summary line containing "avg"
			if strings.Contains(line, "avg") {
				// Split by '=' to get the stats part
				parts := strings.Split(line, "=")
				if len(parts) < 2 {
					continue
				}
				stats := strings.TrimSpace(parts[1])
				// Remove the trailing " ms"
				stats = strings.TrimSuffix(stats, " ms")
				// Split by '/' to get individual metrics
				// Format is usually min/avg/max/stddev
				values := strings.Split(stats, "/")
				if len(values) >= 2 {
					avgStr := values[1]
					return strconv.ParseFloat(avgStr, 64)
				}
			}
		}
	}

	return 0, fmt.Errorf("could not parse average latency from ping output")
}

func main() {
