package main

import (
	"bytes"
	"fmt"
	"os/exec"
	"regexp"
	"runtime"
	"strconv"
)

// MeasureLatency pings the specified host a given number of times and returns the average latency in milliseconds.
func MeasureLatency(host string, count int) (float64, error) {
	var cmd *exec.Cmd

	// Determine the correct arguments based on the operating system
	if runtime.GOOS == "windows" {
		// Windows uses -n for count
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	} else {
		// Linux and macOS use -c for count
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	}

	var stdout, stderr bytes.Buffer
	cmd.Stdout = &stdout
	cmd.Stderr = &stderr

	// Run the command
	err := cmd.Run()
	if err != nil {
		return 0, fmt.Errorf("ping command failed: %v, stderr: %s", err, stderr.String())
	}

	output := stdout.String()

	// Regex to extract time values from ping output.
	// Matches formats like "time=14.2 ms" (Linux/macOS) and "time=14ms" or "time<1ms" (Windows)
	re := regexp.MustCompile(`time[=<](\d+(\.\d+)?)`)
	matches := re.FindAllStringSubmatch(output, -1)

	if len(matches) == 0 {
		return 0, fmt.Errorf("could not parse latency from ping output")
	}

	var totalLatency float64
	for _, match := range matches {
		if len(match) > 1 {
			val, err := strconv.ParseFloat(match[1], 64)
			if err != nil {
				continue
			}
			totalLatency += val
		}
	}

	averageLatency := totalLatency / float64(len(matches))
	return averageLatency, nil
}

func main() {
	host := "google.com"
	count := 4

	avg, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Printf("Error measuring latency: %v\n", err)
		return
	}

	fmt.Printf("Average latency for %s over %d pings: %.2f ms\n", host, count, avg)
}

