package main

import (
	"bytes"
	"errors"
	"fmt"
	"os"
	"os/exec"
	"regexp"
	"runtime"
	"strconv"
)

// MeasureLatency pings the specified host a given number of times and returns the average latency in ms.
func MeasureLatency(host string, count int) (float64, error) {
	if count <= 0 {
		return 0, errors.New("ping count must be greater than 0")
	}

	// Construct the ping command based on the operating system
	// Linux/macOS use -c for count, Windows uses -n
	var cmd *exec.Cmd
	if runtime.GOOS == "windows" {
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	} else {
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	}

	var stdout, stderr bytes.Buffer
	cmd.Stdout = &stdout
	cmd.Stderr = &stderr

	// Run the command
	err := cmd.Run()
	if err != nil {
		// Ping returns non-zero exit code if some packets are lost but some are received.
		// We usually want to proceed if we have partial data, but for simplicity here,
		// we treat execution errors as fatal unless we successfully parse output later.
		// However, checking stderr is good practice.
		if stderr.Len() > 0 {
			return 0, fmt.Errorf("ping command failed: %v, stderr: %s", err, stderr.String())
		}
	}

	output := stdout.String()

	// Regex to extract time from ping output.
	// Handles Linux/Mac format: "time=14.2 ms"
	// Handles Windows format: "time=14ms" or "time<1ms"
	re := regexp.MustCompile(`time[=<](\d+(\.\d+)?)\s*ms`)
	matches := re.FindAllStringSubmatch(output, -1)

	if len(matches) == 0 {
		return 0, errors.New("no latency data found in ping output")
	}

	var totalLatency float64
	for _, match := range matches {
		if len(match) < 2 {
			continue
		}
		// Parse the captured number
		val, err := strconv.ParseFloat(match[1], 64)
		if err != nil {
			continue
		}
		totalLatency += val
	}

	averageLatency := totalLatency / float64(len(matches))
	return averageLatency, nil
}

func main() {
	// Example Usage
	host := "google.com"
	count := 4

	fmt.Printf("Pinging %s %d times...\n", host, count)
	avg, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Printf("Error: %v\n", err)
		os.Exit(1)
	}

	fmt.Printf("Average latency: %.2f ms\n", avg)
}

